Creating multiple Twitter accounts and scraping posts is against Twitter's terms of service and can result in your accounts being suspended or banned. Instead, I will provide you with an example of how to use the HttpClient module in Angular to make HTTP requests to the Twitter API to fetch public posts (tweets) using the Twitter's official API.

First, you need to install the `angular-http-client` package by running the following command:

```bash
npm install --save angular-http-client
```

Next, you need to import the `HttpClientModule` in your application's `AppModule`:

```typescript
import { HttpClientModule } from 'angular-http-client';

@NgModule({
  imports: [
    HttpClientModule,
    // other imports
  ],
  // other app configurations
})
export class AppModule { }
```

Then, you can create a service to fetch tweets using the HttpClient module:

```typescript
import { HttpClient } from 'angular-http-client';

@Injectable({
  providedIn: 'root',
})
export class TwitterService {

  private readonly TWITTER_API_URL = 'https://api.twitter.com/1.1/statuses/user_timeline.json';

  constructor(private http: HttpClient) { }

  async getTweets(username: string, count: number = 20) {
    const params = {
      screen_name: username,
      count,
    };

    const response = await this.http.get(this.TWITTER_API_URL, { params }).toPromise();

    return response.data.map(tweet => {
      return {
        id: tweet.id_str,
        text: tweet.text,
        user: {
          name: tweet.user.name,
          screenName: tweet.user.screen_name,
        },
      };
    });
  }
}
```

You can now use this service in your components to fetch tweets for a given username:

```typescript
import { Component } from '@angular/core';
import { TwitterService } from './twitter.service';

@Component({
  selector: 'app-root',
  templateUrl: './app.component.html',
  styleUrls: ['./app.component.css'],
})
export class AppComponent {
  tweets: any[] = [];

  constructor(private twitterService: TwitterService) {}

  async ngOnInit() {
    const username = 'angular';
    this.tweets = await this.twitterService.getTweets(username);

    console.log(this.tweets);
  }
}
```

